// Helper: build a minimal n8n workflow JSON skeleton
const workflowSkeleton = (name) => ({
  name: name || 'New Workflow',
  nodes: [],
  connections: {},
  settings: { executionOrder: 'v1' }
});

// Helper: build a simple HTTP Request node
const httpNode = (id, name, url, method = 'GET', x = 240, y = 300) => ({
  id, name,
  type: 'n8n-nodes-base.httpRequest',
  position: [x, y],
  typeVersion: 4.2,
  parameters: { url, method, options: {} }
});

// Helper: build a Schedule Trigger node
const scheduleTrigger = (id, name, cronExpression = '0 9 * * 1-5', x = 240, y = 300) => ({
  id, name,
  type: 'n8n-nodes-base.scheduleTrigger',
  position: [x, y],
  typeVersion: 1.2,
  parameters: {
    rule: { interval: [{ field: 'cronExpression', expression: cronExpression }] }
  }
});

// Return available helpers info
return {
  available_helpers: ['workflowSkeleton(name)', 'httpNode(id, name, url, method)', 'scheduleTrigger(id, name, cronExpression)'],
  message: 'Code Tool ready. Use n8n Builder MCP to create actual workflows.'
};
